describe('WebSocket Store', () => {
  it('应该管理连接状态', () => {
    const store = useWebSocketStore()

    expect(store.connected).toBe(false)

    store.connect()
    expect(store.connected).toBe(true)
  })

  it('应该订阅事件', () => {
    const store = useWebSocketStore()
    const handler = vi.fn()

    store.subscribe('agent.status_changed', handler)
    store.emit('agent.status_changed', { data: 'test' })

    expect(handler).toHaveBeenCalledWith({ data: 'test' })
  })

  it('应该持久化配置', () => {
    const store = useWebSocketStore()

    store.setConfig({ autoReconnect: true })

    const config = localStorage.getItem('ws-config')
    expect(config).toContain('autoReconnect')
  })

  it('应该记录事件历史', () => {
    const store = useWebSocketStore()

    store.emit('test.event', { data: 'test' })

    expect(store.eventHistory).toHaveLength(1)
    expect(store.eventHistory[0].event).toBe('test.event')
  })
})
