import { test, expect } from '@playwright/test'

test.describe('WebSocket', () => {
  test('should establish WebSocket connection', async ({ page }) => {
    const wsMessages: string[] = []

    // 监听 WebSocket 消息
    page.on('websocket', ws => {
      ws.on('framereceived', frame => {
        wsMessages.push(frame.payload.toString())
      })
    })

    await page.goto('http://localhost:5173/dashboard')

    // 等待连接建立
    await page.waitForTimeout(1000)

    // 验证收到消息
    expect(wsMessages.length).toBeGreaterThan(0)
  })

  test('should update UI on WebSocket event', async ({ page }) => {
    await page.goto('http://localhost:5173/dashboard')

    // 等待初始状态
    const initialStatus = await page.locator('.agent-card:first-child .agent-status').textContent()

    // 等待 WebSocket 更新
    await page.waitForTimeout(2000)

    const updatedStatus = await page.locator('.agent-card:first-child .agent-status').textContent()

    // 验证状态可能已更新
    expect(updatedStatus).toBeTruthy()
  })

  test('should reconnect on WebSocket disconnect', async ({ page }) => {
    let reconnectAttempts = 0

    page.on('websocket', ws => {
      ws.on('close', () => {
        reconnectAttempts++
      })
    })

    await page.goto('http://localhost:5173/dashboard')

    // 模拟网络断开
    await page.context().setOffline(true)
    await page.waitForTimeout(5000)

    // 恢复网络
    await page.context().setOffline(false)
    await page.waitForTimeout(3000)

    // 验证重连
    expect(reconnectAttempts).toBeGreaterThan(0)
  })
})
