              <span>当前阶段: {{ currentPhase }}</span>
              <span v-if="estimatedTime">预计剩余: {{ estimatedTime }}</span>
            </div>
          </div>

          <div v-if="iteration.requirement" class="requirement-section">
            <h4>需求描述</h4>
            <p>{{ iteration.requirement }}</p>
          </div>

          <div class="agents-section">
            <h4>Agent 执行状态</h4>
            <el-row :gutter="10">
              <el-col :span="6" v-for="agent in agents" :key="agent.agentName">
                <AgentStatusCard :agent="agent" />
              </el-col>
            </el-row>
          </div>
        </div>

        <el-empty v-else description="当前没有正在运行的迭代" />
      </template>
