<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted } from 'vue'
import { useIterationStore } from '@/stores/iteration'
import { useAgentStore } from '@/stores/agent'
import { useWebSocketStore } from '@/stores/websocket'
import AgentStatusCard from './AgentStatusCard.vue'
import { ElMessageBox } from 'element-plus'

const iterationStore = useIterationStore()
const agentStore = useAgentStore()
const wsStore = useWebSocketStore()

const loading = ref(true)
const iteration = ref<any>(null)
const agents = ref<any[]>([])
const progress = ref(0)
const currentPhase = ref('')
const estimatedTime = ref('')

const progressStatus = computed(() => {
  if (progress.value >= 100) return 'success'
  return undefined
})

// 处理暂停
async function handlePause() {
  try {
    await ElMessageBox.confirm('确定要暂停当前迭代吗？', '暂停确认', {
      type: 'warning'
    })
    // 调用 API 暂停
    await iterationStore.pauseIteration(iteration.value.id)
  } catch (e) {
    // 用户取消
  }
}

// 处理停止
async function handleStop() {
  try {
    await ElMessageBox.confirm('确定要停止当前迭代吗？', '停止确认', {
      type: 'warning'
    })
    await iterationStore.stopIteration(iteration.value.id)
  } catch (e) {
    // 用户取消
  }
}

// 处理重启
async function handleRestart() {
  await iterationStore.restartIteration(iteration.value.id)
}

// 监听 WebSocket 事件
onMounted(async () => {
  loading.value = true
  try {
    await iterationStore.fetchCurrentIteration()
    iteration.value = iterationStore.currentIteration

    if (iteration.value?.iteration?.id) {
      await agentStore.fetchAgents(iteration.value.iteration.id)
      agents.value = agentStore.agents
    }
  } finally {
    loading.value = false
  }

  // 监听进度更新
  wsStore.on('iteration.progress', (data) => {
    progress.value = data.progress
    currentPhase.value = data.phase
    if (data.estimatedTime) {
      estimatedTime.value = formatTime(data.estimatedTime)
    }
  })

  // 监听 Agent 状态变化
  wsStore.on('agent.status_changed', (data) => {
    const index = agents.value.findIndex(a => a.agentName === data.agentName)
    if (index !== -1) {
      agents.value[index] = data
    }
  })
})

function formatTime(seconds: number): string {
  const mins = Math.floor(seconds / 60)
  const secs = seconds % 60
  return `${mins}分${secs}秒`
}

// ... 其他代码保持不变
</script>

