**解决方案**:
```typescript
// tests/helpers/mock-sdk.ts
import { jest } from '@jest/globals'

export function setupMockQuery() {
  const mockQuery = jest.fn()

  mockQuery.mockImplementation(() => ({
    async*[Symbol.asyncIterator]() {
      yield { role: 'assistant', content: 'Mocked response' }
    }
  }))

  return mockQuery
}

// tests/history-file-async.test.ts
import { setupMockQuery } from './helpers/mock-sdk'

beforeEach(() => {
  const mockQuery = setupMockQuery()
  jest.mock('@anthropic-ai/claude-agent-sdk', () => ({
    query: mockQuery
  }))
})
```

