import { describe, it, expect, beforeAll, afterAll } from 'vitest'
import { WebSocket } from 'ws'
import { startDashboard } from '@/dashboard/server'

describe('WebSocket集成测试', () => {
  let server: any
  let ws: WebSocket

  beforeAll(async () => {
    server = await startDashboard()
  })

  afterAll(async () => {
    await server.close()
  })

  it('应该建立WebSocket连接', async () => {
    ws = new WebSocket('ws://localhost:3000/api/ws')

    await new Promise((resolve) => {
      ws.on('open', resolve)
    })

    expect(ws.readyState).toBe(WebSocket.OPEN)
  })

  it('应该接收系统指标事件', (done) => {
    ws.on('message', (data) => {
      const { event, payload } = JSON.parse(data.toString())
      if (event === 'system.metrics') {
        expect(payload).toHaveProperty('cpu')
        expect(payload).toHaveProperty('memory')
        done()
      }
    })
  })

  it('应该接收迭代状态事件', (done) => {
    ws.on('message', (data) => {
      const { event, payload } = JSON.parse(data.toString())
      if (event === 'iteration.status_changed') {
        expect(payload).toHaveProperty('id')
        expect(payload).toHaveProperty('status')
        done()
      }
    })
  })

  it('断开后应该自动重连', async () => {
    ws.close()

    await new Promise((resolve) => setTimeout(resolve, 1000))

    // 验证重连逻辑
  })
})
