<template>
  <el-card class="metric-card" @click="handleClick">
    <!-- Loading 状态 -->
    <div v-if="loading" class="metric-skeleton">
      <el-skeleton :rows="2" animated />
    </div>

    <!-- 正常状态 -->
    <div v-else class="metric-content">
      <!-- 标题 -->
      <div class="metric-title">{{ title }}</div>

      <!-- 数值和趋势 -->
      <div class="metric-values">
        <div class="metric-value">{{ formattedValue }}</div>
        <div v-if="trend !== undefined" class="metric-trend" :class="trendClass">
          <el-icon><component :is="trendIcon" /></el-icon>
          <span>{{ Math.abs(trend) }}%</span>
        </div>
      </div>

      <!-- 图标 -->
      <div v-if="icon" class="metric-icon">
        <el-icon :size="32">
          <component :is="icon" />
        </el-icon>
      </div>
    </div>
  </el-card>
</template>

<script setup lang="ts">
import { computed } from 'vue'
import { ArrowUp, ArrowDown, Minus } from '@element-plus/icons-vue'

interface Props {
  title: string
  value: number | string
  icon?: string
  trend?: number
  loading?: boolean
  format?: 'number' | 'percent' | 'currency' | 'duration'
}

const props = withDefaults(defineProps<Props>(), {
  loading: false,
  format: 'number'
})

const emit = defineEmits<{
  click: [event: MouseEvent]
}>()

// 格式化数值
const formattedValue = computed(() => {
  if (props.format === 'percent') {
    return `${props.value}%`
  }
  if (props.format === 'number' && typeof props.value === 'number') {
    return props.value.toLocaleString()
  }
  return props.value
})

// 趋势样式
const trendClass = computed(() => {
  if (!props.trend) return ''
  return props.trend > 0 ? 'trend-up' : props.trend < 0 ? 'trend-down' : 'trend-flat'
})

// 趋势图标
const trendIcon = computed(() => {
  if (!props.trend) return Minus
  return props.trend > 0 ? ArrowUp : ArrowDown
})

const handleClick = (event: MouseEvent) => {
  emit('click', event)
}
</script>

