```typescript
import { useWebSocketStore } from '@/stores/websocket'
import { onMounted, onUnmounted, ref } from 'vue'

const wsStore = useWebSocketStore()
const chartData = ref({
  timestamps: [] as string[],
  cpu: [] as number[],
  memory: [] as number[]
})

// 监听实时数据
onMounted(() => {
  wsStore.on('system.metrics', handleMetricsUpdate)

  // 定时请求指标
  const timer = setInterval(() => {
    wsStore.send({ type: 'request_metrics' })
  }, 3000)

  onUnmounted(() => {
    wsStore.off('system.metrics', handleMetricsUpdate)
    clearInterval(timer)
  })
})

const handleMetricsUpdate = (data: SystemMetrics) => {
  const timestamp = new Date().toLocaleTimeString()

  // 添加新数据
  chartData.value.timestamps.push(timestamp)
  chartData.value.cpu.push(data.cpuUsage)
  chartData.value.memory.push(data.memoryUsage)

  // 限制数据点数量
  if (chartData.value.timestamps.length > 100) {
    chartData.value.timestamps.shift()
    chartData.value.cpu.shift()
    chartData.value.memory.shift()
  }

  // 更新图表
  updateChart()
}
```

