import { createPinia, setActivePinia } from 'pinia'
import SystemResourceChart from '@/components/charts/SystemResourceChart.vue'
import { useWebSocketStore } from '@/stores/websocket'

describe('WebSocket → Chart 集成测试', () => {
  let wsStore: any
  let mockWs: any

  beforeEach(() => {
    setActivePinia(createPinia())
    wsStore = useWebSocketStore()

    // Mock WebSocket
    mockWs = {
      on: vi.fn(),
      send: vi.fn(),
      off: vi.fn()
    }

    vi.spyOn(wsStore, 'on').mockImplementation(mockWs.on)
    vi.spyOn(wsStore, 'send').mockImplementation(mockWs.send)
  })

  afterEach(() => {
    vi.clearAllMocks()
  })

  it('应该建立WebSocket连接', async () => {
    const wrapper = mount(SystemResourceChart)

    expect(wsStore.on).toHaveBeenCalledWith(
      'system.metrics',
      expect.any(Function)
    )
  })

  it('应该接收并处理system.metrics事件', async () => {
    const wrapper = mount(SystemResourceChart)

    // 模拟接收数据
    const metricsData = {
      cpuUsage: 45.5,
      memoryUsage: 62.3,
      timestamp: Date.now()
    }

    const callback = mockWs.on.mock.calls[0][1]
    callback(metricsData)

    await wrapper.vm.$nextTick()

    // 验证图表数据更新
    expect(wrapper.vm.chartData.cpu.length).toBeGreaterThan(0)
    expect(wrapper.vm.chartData.memory.length).toBeGreaterThan(0)
  })

  it('应该限制最大数据点数量', async () => {
    const wrapper = mount(SystemResourceChart)
    const callback = mockWs.on.mock.calls[0][1]

    // 添加超过100个数据点
    for (let i = 0; i < 150; i++) {
      callback({ cpuUsage: i, memoryUsage: i, timestamp: i })
    }

    await wrapper.vm.$nextTick()

    // 应该保持最多100个点
    expect(wrapper.vm.chartData.cpu.length).toBeLessThanOrEqual(100)
  })

  it('应该在组件卸载时清理监听器', async () => {
    const wrapper = mount(SystemResourceChart)
    wrapper.unmount()

    expect(wsStore.off).toHaveBeenCalled()
  })
})
```

