<script setup lang="ts">
import { VideoPause, VideoPlay, CircleClose, Refresh } from '@element-plus/icons-vue'
import { ElMessageBox } from 'element-plus'

const emit = defineEmits<{
  pause: []
  resume: []
  stop: []
  restart: []
}>()

const handlePause = () => {
  emit('pause')
}

const handleResume = () => {
  emit('resume')
}

const handleStop = () => {
  ElMessageBox.confirm('确定要停止当前迭代吗?', '停止确认', {
    type: 'warning'
  }).then(() => {
    emit('stop')
  })
}

const handleRestart = () => {
  ElMessageBox.confirm('确定要重新开始吗?', '重启确认', {
    type: 'info'
  }).then(() => {
    emit('restart')
  })
}
</script>

