import { describe, it, expect, beforeEach, afterEach } from '@jest/globals';
import { WebSocketService } from '../../src/dashboard/services/realtime.service';

describe('WebSocket 连接管理', () => {
  let ws: WebSocketService;

  afterEach(async () => {
    if (ws) {
      await ws.disconnect();
    }
  });

  it('应该成功建立 WebSocket 连接', async () => {
    ws = new WebSocketService();
    await ws.connect('ws://localhost:3000/api/ws');
    expect(ws.isConnected()).toBe(true);
  });

  it('应该在连接失败时自动重试', async () => {
    ws = new WebSocketService();
    try {
      await ws.connect('invalid-url');
    } catch (e) {
      expect(ws.retryCount).toBeGreaterThan(0);
    }
  });

  it('应该定期发送心跳', async () => {
    ws = new WebSocketService();
    const sendSpy = jest.spyOn(ws, 'send');

    await ws.connect('ws://localhost:3000/api/ws');

    // 等待心跳间隔 (30s)
    await new Promise(resolve => setTimeout(resolve, 30000));

    expect(sendSpy).toHaveBeenCalledWith({ type: 'ping' });
  });
});
```

