describe('WebSocket 性能测试', () => {
  it('应该支持 10 个并发连接', async () => {
    const connections = []

    for (let i = 0; i < 10; i++) {
      const ws = new WebSocketService()
      await ws.connect('ws://localhost:3000/api/ws')
      connections.push(ws)
    }

    // 验证所有连接都成功
    connections.forEach(ws => {
      expect(ws.isConnected()).toBe(true)
    })

    // 清理
    await Promise.all(connections.map(ws => ws.disconnect()))
  })

  it('消息推送延迟应该 < 500ms', async () => {
    const ws = new WebSocketService()
    await ws.connect('ws://localhost:3000/api/ws')

    const startTime = Date.now()

    ws.on('message', () => {
      const latency = Date.now() - startTime
      expect(latency).toBeLessThan(500)
    })

    // 触发服务器推送
    await ws.send({ type: 'get_metrics' })
  })
})
```

