### Task 2.1: WebSocket Store 单元测试 (2h)

**优先级**: 🔴 P0 - **关键功能缺失**

**文件**: `tests/dashboard/frontend/stores/websocket.test.ts` (新建)

**测试用例**:
```typescript
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { createPinia, setActivePinia } from 'pinia';
import { useWebSocketStore } from '@/stores/websocket';

describe('WebSocketStore', () => {
  beforeEach(() => {
    setActivePinia(createPinia());
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('应该初始化为未连接状态', () => {
    const store = useWebSocketStore();
    expect(store.isConnected).toBe(false);
    expect(store.connectionStatus).toBe('disconnected');
  });

  it('应该成功连接 WebSocket', async () => {
    const store = useWebSocketStore();
    const mockWs = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      readyState: 1 // OPEN
    };

    global.WebSocket = vi.fn(() => mockWs) as any;

    await store.connect();

    expect(store.isConnected).toBe(true);
    expect(store.connectionStatus).toBe('connected');
  });

  it('应该正确处理连接失败', async () => {
    const store = useWebSocketStore();
    const mockWs = {
      close: vi.fn(),
      addEventListener: vi.fn((event, handler) => {
        if (event === 'error') {
          setTimeout(() => handler(new Error('Connection failed')), 0);
        }
      }),
      readyState: 3 // CLOSED
    };

    global.WebSocket = vi.fn(() => mockWs) as any;

    try {
      await store.connect();
    } catch (error) {
      expect(store.connectionStatus).toBe('error');
    }
  });

  it('应该在连接断开时自动重连', async () => {
    const store = useWebSocketStore({ autoReconnect: true });
    const connectSpy = vi.spyOn(store, 'connect');

    store.handleDisconnect();

    // 等待重连延迟
    await vi.advanceTimersByTimeAsync(1000);

    expect(connectSpy).toHaveBeenCalled();
  });

  it('应该正确处理消息', () => {
    const store = useWebSocketStore();
    const message = {
      event: 'iteration.status_changed',
      data: { id: 1, status: 'running' }
    };

    store.handleMessage(message);

    expect(store.messages).toHaveLength(1);
    expect(store.messages[0]).toEqual(message);
  });

  it('应该定期发送心跳', async () => {
    const store = useWebSocketStore();
    const mockWs = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      readyState: 1
    };
    global.WebSocket = vi.fn(() => mockWs) as any;

    await store.connect();
    const heartbeatSpy = vi.spyOn(store, 'sendHeartbeat');

    store.startHeartbeat();
    await vi.advanceTimersByTimeAsync(30000); // 30秒

    expect(heartbeatSpy).toHaveBeenCalled();
  });

  it('应该能够手动断开连接', async () => {
    const store = useWebSocketStore();
    const mockWs = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      readyState: 1
    };
    global.WebSocket = vi.fn(() => mockWs) as any;

    await store.connect();
    await store.disconnect();

    expect(mockWs.close).toHaveBeenCalled();
    expect(store.isConnected).toBe(false);
  });
});
```

**验收标准**:
- ✅ 所有测试用例通过
- ✅ 覆盖率达到 90%+
- ✅ Mock WebSocket 正确实现

