#### Task 2.3: 心跳和重连测试 🔴 P0
```typescript
describe('WebSocket 心跳和重连', () => {
  let service: RealtimeService;

  beforeEach(async () => {
    service = new RealtimeService();
    await service.start();
  });

  afterEach(async () => {
    await service.stop();
  });

  it('应该定期发送心跳', async () => {
    const mockClient = {
      send: jest.fn(),
      readyState: 1
    };

    service.handleConnection(mockClient);

    // 等待心跳间隔
    await new Promise(resolve => setTimeout(resolve, 35000));

    expect(mockClient.send).toHaveBeenCalledWith(
      expect.stringContaining('heartbeat')
    );
  });

  it('应该检测超时未响应的客户端', async () => {
    const mockClient = {
      send: jest.fn(),
      readyState: 1,
      lastPong: Date.now() - 70000 // 70秒前
    };

    service.handleConnection(mockClient);
    service.checkTimeouts();

    expect(service.getClientCount()).toBe(0);
  });

  it('应该支持客户端自动重连', async () => {
    let reconnectCount = 0;

    const mockClient = {
      send: jest.fn(),
      readyState: 0, // CLOSED
      reconnect: () => {
        reconnectCount++;
        mockClient.readyState = 1;
      }
    };

    service.handleConnection(mockClient);
    service.handleDisconnect(mockClient);

    // 触发重连逻辑
    await new Promise(resolve => setTimeout(resolve, 100));

    expect(reconnectCount).toBeGreaterThan(0);
  });
});
```

