```typescript
// tests/dashboard/frontend/stores/websocket.test.ts (新建)

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { createPinia, setActivePinia } from 'pinia';
import { useWebSocketStore } from '@/stores/websocket';

describe('WebSocketStore', () => {
  beforeEach(() => {
    setActivePinia(createPinia());
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('应该初始化为未连接状态', () => {
    const store = useWebSocketStore();
    expect(store.isConnected).toBe(false);
    expect(store.connectionStatus).toBe('disconnected');
  });

  it('应该成功连接 WebSocket', async () => {
    const store = useWebSocketStore();
    const mockWs = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      readyState: WebSocket.OPEN
    };

    global.WebSocket = vi.fn(() => mockWs) as any;
    await store.connect();

    expect(store.isConnected).toBe(true);
    expect(store.connectionStatus).toBe('connected');
  });

  it('应该正确处理消息', () => {
    const store = useWebSocketStore();
    const message = {
      event: 'iteration.status_changed',
      data: { status: 'running' }
    };

    store.handleMessage(message);
    expect(store.messages).toHaveLength(1);
  });

  it('应该在连接断开时自动重连', async () => {
    const store = useWebSocketStore({ autoReconnect: true });
    const connectSpy = vi.spyOn(store, 'connect');

    store.handleDisconnect();
    await vi.advanceTimersByTimeAsync(1000);

    expect(connectSpy).toHaveBeenCalled();
  });

  it('应该定期发送心跳', async () => {
    const store = useWebSocketStore();
    const heartbeatSpy = vi.spyOn(store, 'sendHeartbeat');

    store.startHeartbeat();
    await vi.advanceTimersByTimeAsync(30000);

    expect(heartbeatSpy).toHaveBeenCalled();
  });
});
```

