    db = await createTestDatabase();
    service = new IterationService(db);
  });

  afterEach(async () => {
    await db.close();
  });

  it('应该成功创建迭代记录', async () => {
    const iteration = await service.create({
      iterationNumber: 1,
      status: 'running',
      requirement: '测试需求'
    });

    expect(iteration.id).toBeDefined();
    expect(iteration.iterationNumber).toBe(1);
    expect(iteration.status).toBe('running');
  });

  it('应该支持分页查询', async () => {
    // 创建 25 条记录
    for (let i = 1; i <= 25; i++) {
      await service.create({
        iterationNumber: i,
        status: 'completed'
      });
    }

    const result = await service.list({ page: 1, pageSize: 10 });

    expect(result.items).toHaveLength(10);
    expect(result.total).toBe(25);
    expect(result.page).toBe(1);
  });

  it('应该支持按状态筛选', async () => {
    await service.create({ iterationNumber: 1, status: 'running' });
    await service.create({ iterationNumber: 2, status: 'completed' });
    await service.create({ iterationNumber: 3, status: 'failed' });

    const result = await service.list({ status: 'running' });

    expect(result.items).toHaveLength(1);
    expect(result.items[0].status).toBe('running');
  });

  it('应该支持搜索', async () => {
    await service.create({
      iterationNumber: 1,
      requirement: '开发用户登录功能'
    });
    await service.create({
      iterationNumber: 2,
      requirement: '优化数据库查询'
    });

    const result = await service.list({ search: '登录' });

    expect(result.items).toHaveLength(1);
    expect(result.items[0].requirement).toContain('登录');
  });

  it('应该正确更新迭代状态', async () => {
    const iteration = await service.create({
      iterationNumber: 1,
      status: 'running'
    });

    const updated = await service.updateStatus(iteration.id, 'completed');

    expect(updated.status).toBe('completed');
  });

  it('应该返回迭代统计信息', async () => {
    await service.create({ iterationNumber: 1, status: 'completed' });
    await service.create({ iterationNumber: 2, status: 'running' });
    await service.create({ iterationNumber: 3, status: 'failed' });

    const stats = await service.getStats();

    expect(stats.total).toBe(3);
    expect(stats.completed).toBe(1);
    expect(stats.running).toBe(1);
    expect(stats.failed).toBe(1);
  });
});
