import { describe, it, expect, beforeEach, afterEach } from '@jest/globals';
import { WebSocketService } from '../../src/dashboard/services/realtime.service';

describe('WebSocket 连接管理', () => {
  let ws: WebSocketService;

  afterEach(async () => {
    if (ws) await ws.disconnect();
  });

  it('应该成功建立 WebSocket 连接', async () => {
    ws = new WebSocketService();
    await ws.connect();
    expect(ws.isConnected()).toBe(true);
  });

  it('应该在连接失败时重试', async () => {
    ws = new WebSocketService();
    try {
      await ws.connect('invalid-url');
    } catch (e) {
      expect(ws.getRetryCount()).toBeGreaterThan(0);
    }
  });

  it('应该正确处理连接超时', async () => {
    ws = new WebSocketService({ timeout: 1000 });
    const startTime = Date.now();
    try {
      await ws.connect('ws://localhost:9999'); // 不存在的服务器
    } catch (e) {
      const duration = Date.now() - startTime;
      expect(duration).toBeLessThan(2000);
    }
  });
});
```

