describe('心跳和重连机制', () => {
  it('应该定期发送心跳包', async (done) => {
    const ws = new WebSocketService({ heartbeatInterval: 1000 });
    await ws.connect();

    let heartbeatCount = 0;
    ws.on('heartbeat', () => {
      heartbeatCount++;
      if (heartbeatCount >= 3) done();
    });
  });

  it('应该在心跳超时时重连', async (done) => {
    const ws = new WebSocketService({ 
      heartbeatInterval: 500,
      heartbeatTimeout: 1500 
    });

    await ws.connect();

    // 模拟服务器无响应
