    await expect(page.locator('.iteration-table')).toBeVisible();

    // 4. 查看Agent监控
    await page.click('text=Agent 监控');
    await expect(page.locator('.agent-card')).toHaveCount(10);

    // 5. 查看日志
    await page.click('text=日志中心');
    await expect(page.locator('.log-viewer')).toBeVisible();
  });

  test('实时数据更新', async ({ page }) => {
    await page.goto('http://localhost:5173');

    const initialCount = await page.locator('.metric-card:first-child .value').textContent();

    // 触发新迭代
    await page.evaluate(async () => {
      await fetch('/api/iterations', {
        method: 'POST',
        body: JSON.stringify({ iterationNumber: 1, status: 'running' })
      });
    });

    await page.waitForTimeout(1000);
    const newCount = await page.locator('.metric-card:first-child .value').textContent();
    expect(parseInt(newCount)).toBe(parseInt(initialCount) + 1);
  });
});
