```typescript
import { describe, it, expect, beforeEach, afterEach, jest } from '@jest/globals';
import { WebSocket } from 'ws';
import { startDashboard, stopDashboard } from '../../src/dashboard/server';

describe('Dashboard WebSocket - 实时通信测试', () => {
  let server: any;
  let ws: WebSocket;

  beforeAll(async () => {
    // 启动测试服务器
    server = await startDashboard({
      port: 3001,
      enableWebSocket: true
    });
  });

  afterAll(async () => {
    if (ws) ws.close();
    if (server) await stopDashboard();
  });

  afterEach(async () => {
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.close();
    }
  });

  describe('WebSocket 连接管理', () => {
    it('应该成功建立 WebSocket 连接', (done) => {
      ws = new WebSocket('ws://localhost:3001/api/ws');

      ws.on('open', () => {
        expect(ws.readyState).toBe(WebSocket.OPEN);
        done();
      });

      ws.on('error', (error) => {
        done(error);
      });
    });

    it('应该在连接后收到欢迎消息', (done) => {
      ws = new WebSocket('ws://localhost:3001/api/ws');

      ws.on('message', (data) => {
        const message = JSON.parse(data.toString());
        expect(message.event).toBe('connected');
        expect(message.data).toHaveProperty('timestamp');
        done();
      });

      ws.on('error', (error) => {
        done(error);
      });
    });

    it('应该处理连接失败并重试', (done) => {
      const invalidWs = new WebSocket('ws://localhost:9999/api/ws');

      invalidWs.on('error', () => {
        // 连接失败是预期的
        expect(true).toBe(true);
        invalidWs.close();
        done();
      });
    });
  });

  describe('实时数据推送', () => {
    beforeEach((done) => {
      ws = new WebSocket('ws://localhost:3001/api/ws');
      ws.on('open', () => done());
      ws.on('error', (error) => done(error));
    });

    it('应该接收迭代状态更新', (done) => {
      ws.on('message', (data) => {
        const message = JSON.parse(data.toString());

        if (message.event === 'iteration.status_changed') {
          expect(message.data).toHaveProperty('iterationId');
          expect(message.data).toHaveProperty('status');
          done();
        }
      });

      // 模拟发送状态更新
      ws.send(JSON.stringify({
        action: 'subscribe',
        channel: 'iterations'
      }));
    });

    it('应该接收 Agent 状态更新', (done) => {
      ws.on('message', (data) => {
        const message = JSON.parse(data.toString());

        if (message.event === 'agent.status_changed') {
          expect(message.data).toHaveProperty('agentName');
          expect(message.data).toHaveProperty('status');
          done();
        }
      });

      ws.send(JSON.stringify({
        action: 'subscribe',
        channel: 'agents'
      }));
    });

    it('应该接收系统指标更新', (done) => {
      let receivedMetrics = false;

      ws.on('message', (data) => {
        const message = JSON.parse(data.toString());

        if (message.event === 'system.metrics') {
          expect(message.data).toHaveProperty('cpu');
          expect(message.data).toHaveProperty('memory');
          receivedMetrics = true;
          done();
        }
      });

      ws.send(JSON.stringify({
        action: 'subscribe',
        channel: 'system'
      }));

      // 设置超时，防止一直等待
      setTimeout(() => {
        if (!receivedMetrics) {
          done(new Error('未收到系统指标'));
        }
      }, 2000);
    });
  });

  describe('心跳和重连', () => {
    it('应该定期发送心跳', (done) => {
      let heartbeatCount = 0;

      ws = new WebSocket('ws://localhost:3001/api/ws');

      ws.on('message', (data) => {
        const message = JSON.parse(data.toString());

        if (message.event === 'heartbeat') {
          heartbeatCount++;
          if (heartbeatCount >= 2) {
            done();
          }
        }
      });

      ws.on('error', (error) => done(error));
    }, 10000); // 增加超时时间

    it('应该在连接断开后自动重连', (done) => {
      let reconnectAttempts = 0;

      ws = new WebSocket('ws://localhost:3001/api/ws');

      ws.on('open', () => {
        // 模拟网络断开
        ws.terminate();
      });

      ws.on('close', () => {
        reconnectAttempts++;
        if (reconnectAttempts > 1) {
          done();
        }
      });

      ws.on('error', () => {
        // 忽略错误
      });
    }, 15000);
  });

  describe('订阅管理', () => {
    beforeEach((done) => {
      ws = new WebSocket('ws://localhost:3001/api/ws');
      ws.on('open', () => done());
      ws.on('error', (error) => done(error));
    });

    it('应该支持订阅特定频道', (done) => {
      ws.send(JSON.stringify({
        action: 'subscribe',
        channel: 'iterations'
      }));

      // 给服务器时间处理订阅
      setTimeout(() => {
        // 验证订阅成功（这里简化处理）
        expect(true).toBe(true);
        done();
      }, 500);
    });

    it('应该支持取消订阅', (done) => {
      ws.send(JSON.stringify({
        action: 'subscribe',
        channel: 'iterations'
      }));

      setTimeout(() => {
        ws.send(JSON.stringify({
          action: 'unsubscribe',
          channel: 'iterations'
        }));

        setTimeout(() => {
          // 验证取消订阅成功
          expect(true).toBe(true);
          done();
        }, 500);
      }, 500);
    });

    it('应该支持同时订阅多个频道', (done) => {
      ws.send(JSON.stringify({
        action: 'subscribe',
        channels: ['iterations', 'agents', 'system']
      }));

      setTimeout(() => {
        // 验证多频道订阅成功
        expect(true).toBe(true);
        done();
      }, 500);
    });
  });
});
