    expect(store.iterations).toEqual([]);
    expect(store.currentIteration).toBeNull();
    expect(store.totalIterations).toBe(0);
  });

  it('应该添加迭代', () => {
    const store = useIterationStore();

    store.addIteration({
      id: 1,
      iterationNumber: 1,
      status: 'running',
      requirement: 'Test'
    });

    expect(store.iterations).toHaveLength(1);
  });

  it('应该更新迭代状态', () => {
    const store = useIterationStore();
    store.addIteration({ id: 1, status: 'running', requirement: 'Test' });

    store.updateIterationStatus(1, 'completed');

    expect(store.iterations[0].status).toBe('completed');
  });

